import { isNull, loadProperty } from "@tsparticles/engine";
export class Explode {
    maxSizeFactor = 3;
    speed = 2;
    load(data) {
        if (isNull(data)) {
            return;
        }
        loadProperty(this, "maxSizeFactor", data.maxSizeFactor);
        loadProperty(this, "speed", data.speed);
    }
}
